 16→
 17→var configuredModels = signal([]);
 18→var providerMetaSig = signal(new Map());
 19→var loading = signal(false);
 20→var detectingModels = signal(false);
 21→var detectSummary = signal(null);
 22→var detectError = signal("");
 23→var detectProgress = signal(null);
 24→var deletingProvider = signal("");
 25→var providerActionError = signal("");
 26→
 27→function countUniqueProviders(models) {
 28→	return new Set(models.map((m) => m.provider)).size;
 29→}
 30→
 31→function progressFromPayload(payload) {
 32→	return {
 33→		total: payload?.total || 0,
 34→		checked: payload?.checked || 0,
 35→		supported: payload?.supported || 0,
 36→		unsupported: payload?.unsupported || 0,
 37→		errors: payload?.errors || 0,
 38→	};
 39→}
 40→
 41→function handleModelsUpdatedEvent(payload) {
 42→	if (!payload?.phase) return;
 43→	if (payload.phase === "start") {
 44→		detectingModels.value = true;
 45→		detectError.value = "";
 46→		detectSummary.value = null;
 47→		detectProgress.value = progressFromPayload(payload);
 48→		return;
 49→	}
 50→	if (payload.phase === "progress") {
 51→		detectingModels.value = true;
 52→		detectProgress.value = progressFromPayload(payload);
 53→		return;
 54→	}
 55→	if (payload.phase === "complete") {
 56→		detectingModels.value = false;
 57→		if (payload.summary) {
 58→			detectSummary.value = payload.summary;
 59→			detectProgress.value = progressFromPayload(payload.summary);
 60→		}
 61→		return;
 62→	}
 63→	if (payload.phase === "cancelled") {
 64→		detectingModels.value = false;
 65→		detectError.value = t("providers:detectionCancelled");
 66→		if (payload.summary) {
 67→			detectSummary.value = payload.summary;
 68→			detectProgress.value = progressFromPayload(payload.summary);
 69→		}
 70→		return;
 71→	}
 72→	if (payload.phase === "error") {
 73→		detectingModels.value = false;
 74→		detectError.value = payload.error || t("providers:modelDetectionFailed");
 75→	}
 76→}
 77→
 78→function fetchProviders() {
 79→	loading.value = true;
 80→	return Promise.all([sendRpc("models.list_all", {}), sendRpc("providers.available", {})])
 81→		.then(([modelsRes, providersRes]) => {
 82→			loading.value = false;
 83→			var providerMeta = new Map();
 84→			var configuredProviders = [];
 85→			if (providersRes?.ok) {
 86→				configuredProviders = (providersRes.payload || []).filter(
 87→					(configuredProvider) => configuredProvider.configured,
 88→				);
 89→				for (var providerMetaEntry of providersRes.payload || []) {
 90→					providerMeta.set(providerMetaEntry.name, providerMetaEntry);
 91→				}
 92→			}
 93→			providerMetaSig.value = providerMeta;
 94→
 95→			var models = [];
 96→			if (modelsRes?.ok) {
 97→				models = (modelsRes.payload || []).map((m) => ({
 98→					...m,
 99→					providerDisplayName: providerMeta.get(m.provider)?.displayName || m.provider,
100→					authType: providerMeta.get(m.provider)?.authType || "api-key",
101→				}));
102→			}
103→
104→			// Include configured providers that don't currently expose a model.
105→			var modelProviders = new Set(models.map((m) => m.provider));
106→			var providerOnlyRows = [];
107→			providerOnlyRows = configuredProviders
108→				.filter((providerWithoutModels) => !modelProviders.has(providerWithoutModels.name))
109→				.map((providerWithoutModels) => ({
110→					id: `provider:${providerWithoutModels.name}`,
111→					provider: providerWithoutModels.name,
112→					displayName: providerWithoutModels.displayName,
113→					providerDisplayName: providerWithoutModels.displayName,
114→					providerOnly: true,
115→					authType: providerWithoutModels.authType,
116→				}));
117→
118→			configuredModels.value = [...models, ...providerOnlyRows];
119→			updateNavCount("providers", countUniqueProviders(configuredModels.value));
120→		})
121→		.catch(() => {
122→			loading.value = false;
123→		});
124→}
125→
126→async function runDetectAllModels() {
127→	if (!connected.value || detectingModels.value) return;
128→	detectingModels.value = true;
129→	detectSummary.value = null;
130→	detectError.value = "";
131→	detectProgress.value = null;
132→
133→	try {
134→		// Phase 1: show current full list first before probing.
135→		await Promise.all([fetchModels(), fetchProviders()]);
136→		await new Promise((resolve) => {
137→			requestAnimationFrame(resolve);
138→		});
139→
140→		var res = await sendRpc("models.detect_supported", {});
141→		if (!res?.ok) {
142→			detectError.value = res?.error?.message || t("providers:failedToDetectModels");
143→			detectingModels.value = false;
144→			return;
145→		}
146→		if (res.payload?.skipped) {
147→			detectingModels.value = false;
148→			return;
149→		}
150→		detectSummary.value = res.payload || null;
151→		detectProgress.value = progressFromPayload(res.payload);
152→		await Promise.all([fetchModels(), fetchProviders()]);
153→		var p = detectProgress.value;
154→		if (!p || p.total === 0 || p.checked >= p.total) {
155→			detectingModels.value = false;
156→		}
157→	} catch (_err) {
158→		detectingModels.value = false;
159→	}
160→}
161→
162→async function cancelDetection() {
163→	var res = await sendRpc("models.cancel_detect", {});
164→	if (!res?.ok) {
165→		detectError.value = res?.error?.message || t("providers:modelDetectionFailed");
166→	}
167→}
168→
169→function groupProviderRows(models, metaMap) {
170→	var groups = new Map();
171→	for (var row of models) {
172→		var key = row.provider;
173→		if (!groups.has(key)) {
174→			groups.set(key, {
175→				provider: key,
176→				providerDisplayName: row.providerDisplayName || row.displayName || key,
177→				authType: row.authType || "api-key",
178→				selectedModel: metaMap?.get(key)?.model || null,
179→				models: [],
180→			});
181→		}
182→		var groupEntry = groups.get(key);
183→		if (!row.providerOnly) {
184→			groupEntry.models.push(row);
185→		}
186→	}
187→
188→	var result = Array.from(groups.values());
189→	result.sort((a, b) => {
190→		var aOrder = metaMap?.get(a.provider)?.uiOrder;
191→		var bOrder = metaMap?.get(b.provider)?.uiOrder;
192→		var hasAOrder = Number.isFinite(aOrder);
193→		var hasBOrder = Number.isFinite(bOrder);
194→		if (hasAOrder && hasBOrder && aOrder !== bOrder) return aOrder - bOrder;
195→		if (hasAOrder && !hasBOrder) return -1;
196→		if (!hasAOrder && hasBOrder) return 1;
197→		return a.providerDisplayName.localeCompare(b.providerDisplayName);
198→	});
199→	for (var providerGroup of result) {
200→		providerGroup.models.sort((a, b) => {
201→			// Preferred > recommended > newest date > highest version number > alpha.
202→			var aPref = a.preferred ? 1 : 0;
203→			var bPref = b.preferred ? 1 : 0;
204→			if (aPref !== bPref) return bPref - aPref;
205→			var aRec = a.recommended ? 1 : 0;
206→			var bRec = b.recommended ? 1 : 0;
207→			if (aRec !== bRec) return bRec - aRec;
208→			var aTime = a.createdAt || 0;
209→			var bTime = b.createdAt || 0;
210→			if (aTime !== bTime) return bTime - aTime;
211→			var aVer = modelVersionScore(a.id);
212→			var bVer = modelVersionScore(b.id);
213→			if (aVer !== bVer) return bVer - aVer;
214→			return (a.displayName || a.id).localeCompare(b.displayName || b.id);
215→		});
216→	}
217→	return result;
218→}
