  2→//!
  3→//! This module provides reusable functions for parsing OpenAI-style SSE streams
  4→//! that include tool calls. Used by openai.rs, github_copilot.rs, and kimi_code.rs.
  5→
  6→use std::collections::{HashMap, HashSet};
  7→
  8→use {serde::Serialize, tracing::trace};
  9→
 10→use moltis_agents::model::{
 11→    ChatMessage, CompletionResponse, StreamEvent, ToolCall, Usage, UserContent,
 12→};
 13→
 14→// ============================================================================
 15→// OpenAI Tool Schema Types
 16→// ============================================================================
 17→// These types enforce the correct structure for OpenAI-compatible APIs.
 18→// Using typed structs instead of manual JSON prevents missing fields at compile time.
 19→//
 20→// References:
 21→// - Chat Completions: https://platform.openai.com/docs/guides/function-calling
 22→// - Responses API: https://learn.microsoft.com/en-us/azure/ai-foundry/openai/how-to/responses
 23→// ============================================================================
 24→
 25→/// Chat Completions API tool format (nested under "function").
 26→///
 27→/// ```json
 28→/// { "type": "function", "function": { "name": "...", ... } }
 29→/// ```
 30→#[derive(Debug, Serialize)]
 31→pub struct ChatCompletionsTool {
 32→    #[serde(rename = "type")]
 33→    pub tool_type: &'static str,
 34→    pub function: ChatCompletionsFunction,
 35→}
 36→
 37→/// The function definition nested inside ChatCompletionsTool.
 38→#[derive(Debug, Serialize)]
 39→pub struct ChatCompletionsFunction {
 40→    pub name: String,
 41→    pub description: String,
 42→    pub parameters: serde_json::Value,
 43→    pub strict: bool,
 44→}
 45→
 46→/// Responses API tool format (flat, name at top level).
 47→///
 48→/// ```json
 49→/// { "type": "function", "name": "...", "parameters": {...}, "strict": true }
 50→/// ```
 51→#[derive(Debug, Serialize)]
 52→pub struct ResponsesApiTool {
 53→    #[serde(rename = "type")]
 54→    pub tool_type: &'static str,
 55→    pub name: String,
 56→    pub description: String,
 57→    pub parameters: serde_json::Value,
 58→    pub strict: bool,
 59→}
 60→
 61→/// Make a JSON Schema node nullable by adding `"null"` to its type.
 62→///
 63→/// For schemas using `"type": "string"` (or any single type), this converts to
 64→/// `"type": ["string", "null"]`.  For schemas using `anyOf`/`oneOf`, it appends
 65→/// a `{"type": "null"}` variant.  Already-nullable schemas are left unchanged.
 66→fn make_nullable(schema: &mut serde_json::Value) {
 67→    let Some(obj) = schema.as_object_mut() else {
 68→        return;
 69→    };
 70→
 71→    // If it already has a "null" type, nothing to do.
 72→    if let Some(ty) = obj.get("type") {
 73→        if ty.as_str() == Some("null") {
 74→            return;
 75→        }
 76→        if let Some(arr) = ty.as_array()
 77→            && arr.iter().any(|v| v.as_str() == Some("null"))
 78→        {
 79→            return;
 80→        }
 81→    }
 82→
 83→    // Case 1: has a `type` field — convert to array form with "null".
 84→    if let Some(ty) = obj.get("type").cloned() {
 85→        if let Some(s) = ty.as_str() {
 86→            obj.insert("type".to_string(), serde_json::json!([s, "null"]));
 87→        } else if let Some(arr) = ty.as_array() {
 88→            let mut new_arr = arr.clone();
 89→            new_arr.push(serde_json::json!("null"));
 90→            obj.insert("type".to_string(), serde_json::Value::Array(new_arr));
 91→        }
 92→        return;
 93→    }
 94→
 95→    // Case 2: uses anyOf/oneOf — append a null variant.
 96→    for key in ["anyOf", "oneOf"] {
 97→        if let Some(variants) = obj.get_mut(key).and_then(|v| v.as_array_mut()) {
 98→            let has_null = variants
 99→                .iter()
100→                .any(|v| v.get("type").and_then(|t| t.as_str()) == Some("null"));
101→            if !has_null {
102→                variants.push(serde_json::json!({"type": "null"}));
103→            }
104→            return;
105→        }
106→    }
107→}
