  1→//! Structured error parsing for chat error messages.
  2→//!
  3→//! Converts raw error strings from agent runners / LLM providers into
  4→//! structured JSON payloads that the frontend can render directly.
  5→
  6→use serde_json::Value;
  7→
  8→/// Parse a raw error string into a structured error object with `type`, `icon`,
  9→/// `title`, `detail`, and optionally `provider`, `resetsAt`, and
 10→/// `retryAfterMs` fields.
 11→pub fn parse_chat_error(raw: &str, provider_name: Option<&str>) -> Value {
 12→    let mut error = try_parse_known_error(raw);
 13→
 14→    if let Some(name) = provider_name
 15→        && let Some(obj) = error.as_object_mut()
 16→    {
 17→        obj.insert("provider".into(), Value::String(name.to_string()));
 18→    }
 19→
 20→    error
 21→}
 22→
 23→fn try_parse_known_error(raw: &str) -> Value {
 24→    // Max iterations reached — before JSON parsing since the message is plain text.
 25→    if raw.contains("agent loop exceeded max iterations") {
 26→        let limit = raw
 27→            .rsplit('(')
 28→            .next()
 29→            .and_then(|s| s.trim_end_matches(')').trim().parse::<u64>().ok())
 30→            .unwrap_or(25);
 31→        let mut err = build_error(
 32→            "max_iterations_reached",
 33→            "\u{1F504}",
 34→            "Iteration limit reached",
 35→            &format!(
 36→                "The agent stopped after {} iterations. You can continue if needed.",
 37→                limit
 38→            ),
 39→            None,
 40→            None,
 41→            Some(serde_json::json!({ "limit": limit })),
 42→        );
 43→        if let Some(obj) = err.as_object_mut() {
 44→            obj.insert("canContinue".into(), Value::Bool(true));
 45→        }
 46→        return err;
 47→    }
 48→
 49→    let http_status = extract_http_status(raw);
 50→
 51→    // Try to extract embedded JSON from the error string.
 52→    if let Some(start) = raw.find('{')
 53→        && let Ok(parsed) = serde_json::from_str::<Value>(&raw[start..])
 54→    {
 55→        let err_obj = parsed.get("error").unwrap_or(&parsed);
 56→
 57→        // Usage limit
 58→        if matches_type_or_message(err_obj, "usage_limit_reached", "usage limit") {
 59→            let plan_type = err_obj
 60→                .get("plan_type")
 61→                .and_then(|v| v.as_str())
 62→                .unwrap_or("current");
 63→            let resets_at = extract_resets_at(err_obj);
 64→            return build_error(
 65→                "usage_limit_reached",
 66→                "",
 67→                "Usage limit reached",
 68→                &format!("Your {} plan limit has been reached.", plan_type),
 69→                resets_at,
 70→                None,
 71→                Some(serde_json::json!({ "planType": plan_type })),
 72→            );
 73→        }
 74→
 75→        // Billing / quota exhaustion (not transient rate limiting).
 76→        if is_insufficient_quota_error(err_obj, raw) {
 77→            let detail = err_obj.get("message").and_then(|v| v.as_str()).unwrap_or(
 78→                "Your account quota is exhausted. Add funds or switch providers and try again.",
 79→            );
 80→            return build_error(
 81→                "billing_exhausted",
 82→                "\u{26A0}\u{FE0F}",
 83→                "Insufficient quota",
 84→                detail,
 85→                None,
 86→                None,
 87→                None,
 88→            );
 89→        }
 90→
 91→        // Rate limit
 92→        if matches_type_or_message(err_obj, "rate_limit_exceeded", "rate limit")
 93→            || matches_type_or_message(err_obj, "rate_limit_exceeded", "quota exceeded")
 94→            || http_status == Some(429)
 95→        {
 96→            let detail = err_obj
 97→                .get("message")
 98→                .and_then(|v| v.as_str())
 99→                .unwrap_or("Too many requests. Please wait a moment.");
100→            let resets_at = extract_resets_at(err_obj);
101→            let retry_after_ms = extract_retry_after_ms(raw, err_obj);
102→            return build_error(
103→                "rate_limit_exceeded",
104→                "\u{26A0}\u{FE0F}",
105→                "Rate limited",
106→                detail,
107→                resets_at,
108→                retry_after_ms,
109→                None,
110→            );
111→        }
112→
113→        // Generic JSON error with a message field
114→        if let Some(msg) = extract_message(err_obj)
115→            && is_unsupported_model_message(msg)
116→        {
117→            return build_error(
118→                "unsupported_model",
119→                "\u{26A0}\u{FE0F}",
120→                "Model not supported",
121→                msg,
122→                None,
123→                None,
124→                None,
125→            );
126→        }
127→
128→        // Generic JSON error with a message field
129→        if let Some(msg) = err_obj.get("message").and_then(|v| v.as_str()) {
130→            return build_error(
131→                "api_error",
132→                "\u{26A0}\u{FE0F}",
133→                "Error",
134→                msg,
135→                None,
136→                None,
137→                None,
138→            );
139→        }
140→    }
141→
142→    // Check for HTTP status codes in the raw message.
143→    if is_insufficient_quota_error(&Value::Null, raw) {
144→        return build_error(
145→            "billing_exhausted",
146→            "\u{26A0}\u{FE0F}",
147→            "Insufficient quota",
148→            raw,
149→            None,
150→            None,
151→            None,
152→        );
153→    }
154→
155→    if let Some(code) = http_status {
156→        match code {
157→            401 | 403 => {
158→                return build_error(
159→                    "auth_error",
160→                    "\u{1F512}",
161→                    "Authentication error",
162→                    "Your session may have expired or credentials are invalid.",
163→                    None,
164→                    None,
165→                    None,
166→                );
167→            },
168→            404 => {
169→                return build_error(
170→                    "model_not_found",
171→                    "\u{26A0}\u{FE0F}",
172→                    "Model not found",
173→                    "The requested model was not found. Check that the model name is correct and is available at the endpoint.",
174→                    None,
175→                    None,
176→                    None,
177→                );
178→            },
179→            429 => {
180→                let retry_after_ms = extract_retry_after_ms(raw, &Value::Null);
181→                return build_error(
182→                    "rate_limit_exceeded",
183→                    "",
184→                    "Rate limited",
185→                    "Too many requests. Please wait a moment and try again.",
186→                    None,
187→                    retry_after_ms,
188→                    None,
189→                );
190→            },
191→            code if code >= 500 => {
192→                return build_error(
193→                    "server_error",
194→                    "\u{1F6A8}",
195→                    "Server error",
196→                    "The upstream provider returned an error. Please try again later.",
197→                    None,
198→                    None,
199→                    None,
200→                );
201→            },
202→            _ => {},
203→        }
204→    }
205→
206→    if is_unsupported_model_message(raw) {
207→        return build_error(
208→            "unsupported_model",
209→            "\u{26A0}\u{FE0F}",
210→            "Model not supported",
211→            raw,
212→            None,
213→            None,
214→            None,
215→        );
216→    }
217→
218→    // Default: pass through raw message.
219→    build_error(
220→        "unknown",
221→        "\u{26A0}\u{FE0F}",
222→        "Error",
223→        raw,
224→        None,
225→        None,
226→        None,
227→    )
228→}
