230→fn extract_message(obj: &Value) -> Option<&str> {
231→    obj.get("detail")
232→        .and_then(|v| v.as_str())
233→        .or_else(|| obj.get("message").and_then(|v| v.as_str()))
234→        .or_else(|| {
235→            obj.get("error")
236→                .and_then(|v| v.get("message"))
237→                .and_then(|v| v.as_str())
238→        })
239→        .or_else(|| {
240→            obj.get("error")
241→                .and_then(|v| v.get("detail"))
242→                .and_then(|v| v.as_str())
243→        })
244→}
