246→fn is_unsupported_model_message(message: &str) -> bool {
247→    let lower = message.to_ascii_lowercase();
248→
249→    // Non-chat modality errors (audio, image, video models probed via chat
250→    // completion). These don't mention "model" or "supported" but clearly
251→    // indicate the model isn't meant for /v1/chat/completions.
252→    if lower.contains("input content or output modality contain audio")
253→        || lower.contains("requires audio")
254→    {
255→        return true;
256→    }
257→
258→    let has_model = lower.contains("model");
259→    let unsupported = lower.contains("not supported")
260→        || lower.contains("unsupported")
261→        || lower.contains("not available")
262→        || lower.contains("not a chat model")
263→        || lower.contains("does not support chat")
264→        || lower.contains("only supported in v1/responses")
265→        || lower.contains("v1/chat/completions");
266→    has_model && unsupported
267→}
