269→fn matches_type_or_message(obj: &Value, type_str: &str, message_substr: &str) -> bool {
270→    if let Some(t) = obj.get("type").and_then(|v| v.as_str())
271→        && t == type_str
272→    {
273→        return true;
274→    }
275→    if let Some(m) = obj.get("message").and_then(|v| v.as_str())
276→        && m.to_lowercase().contains(message_substr)
277→    {
278→        return true;
279→    }
280→    false
281→}
