283→fn is_insufficient_quota_error(obj: &Value, raw: &str) -> bool {
284→    if obj
285→        .get("type")
286→        .and_then(|v| v.as_str())
287→        .is_some_and(|t| t.eq_ignore_ascii_case("insufficient_quota"))
288→    {
289→        return true;
290→    }
291→    if obj
292→        .get("code")
293→        .and_then(|v| v.as_str())
294→        .is_some_and(|c| c.eq_ignore_ascii_case("insufficient_quota"))
295→    {
296→        return true;
297→    }
298→    if obj
299→        .get("message")
300→        .and_then(|v| v.as_str())
301→        .is_some_and(|m| {
302→            let lower = m.to_ascii_lowercase();
303→            lower.contains("insufficient_quota")
304→                || (lower.contains("current quota") && lower.contains("billing"))
305→        })
306→    {
307→        return true;
308→    }
309→
310→    raw.to_ascii_lowercase().contains("insufficient_quota")
311→}
