317→fn parse_retry_delay_ms_from_fragment(
318→    fragment: &str,
319→    unit_default_ms: bool,
320→    max_ms: u64,
321→) -> Option<u64> {
322→    let start = fragment.find(|c: char| c.is_ascii_digit())?;
323→    let tail = &fragment[start..];
324→    let digits_len = tail.chars().take_while(|c| c.is_ascii_digit()).count();
325→    if digits_len == 0 {
326→        return None;
327→    }
328→    let amount = tail[..digits_len].parse::<u64>().ok()?;
329→    let unit = tail[digits_len..].trim_start();
330→
331→    let ms = if unit.starts_with("ms") || unit.starts_with("millisecond") {
332→        amount
333→    } else if unit.starts_with("sec") || unit.starts_with("second") || unit.starts_with('s') {
334→        amount.saturating_mul(1_000)
335→    } else if unit.starts_with("min") || unit.starts_with("minute") || unit.starts_with('m') {
336→        amount.saturating_mul(60_000)
337→    } else if unit_default_ms {
338→        amount
339→    } else {
340→        amount.saturating_mul(1_000)
341→    };
342→
343→    Some(ms.clamp(1, max_ms))
344→}
345→
346→fn extract_retry_after_ms(raw: &str, err_obj: &Value) -> Option<u64> {
347→    const MAX_RETRY_AFTER_MS: u64 = 86_400_000;
348→
349→    if let Some(ms) = err_obj.get("retry_after_ms").and_then(|v| v.as_u64()) {
350→        return Some(ms.clamp(1, MAX_RETRY_AFTER_MS));
351→    }
352→    if let Some(seconds) = err_obj.get("retry_after_seconds").and_then(|v| v.as_u64()) {
353→        return Some(seconds.saturating_mul(1_000).clamp(1, MAX_RETRY_AFTER_MS));
354→    }
355→    if let Some(seconds) = err_obj.get("retry_after").and_then(|v| v.as_u64()) {
356→        return Some(seconds.saturating_mul(1_000).clamp(1, MAX_RETRY_AFTER_MS));
357→    }
358→
359→    let lower = raw.to_ascii_lowercase();
360→    for (needle, default_ms) in [
361→        ("retry_after_ms=", true),
362→        ("retry-after-ms=", true),
363→        ("retry_after=", false),
364→        ("retry-after:", false),
365→        ("retry after ", false),
366→        ("retry in ", false),
367→    ] {
368→        if let Some(idx) = lower.find(needle) {
369→            let fragment = &lower[idx + needle.len()..];
370→            if let Some(ms) =
371→                parse_retry_delay_ms_from_fragment(fragment, default_ms, MAX_RETRY_AFTER_MS)
372→            {
373→                return Some(ms);
374→            }
375→        }
376→    }
377→
378→    None
379→}
380→
381→fn extract_http_status(raw: &str) -> Option<u16> {
382→    // Match patterns like "HTTP 429", "status 503", "status: 401", "status=429"
383→    let patterns = ["HTTP ", "status= ", "status=", "status: ", "status "];
384→    for pat in &patterns {
385→        if let Some(idx) = raw.find(pat) {
386→            let after = &raw[idx + pat.len()..];
387→            let digits: String = after.chars().take_while(|c| c.is_ascii_digit()).collect();
388→            if let Ok(code) = digits.parse::<u16>() {
389→                return Some(code);
390→            }
391→        }
392→    }
393→    None
394→}
395→
396→fn build_error(
397→    error_type: &str,
398→    icon: &str,
399→    title: &str,
400→    detail: &str,
401→    resets_at: Option<u64>,
402→    retry_after_ms: Option<u64>,
403→    detail_params: Option<Value>,
404→) -> Value {
405→    let mut obj = serde_json::json!({
406→        "type": error_type,
407→        "icon": icon,
408→        "title": title,
409→        "detail": detail,
410→    });
411→    if let Some(map) = obj.as_object_mut() {
412→        let (title_key, detail_key) = translation_keys_for(error_type);
413→        if let Some(key) = title_key {
414→            map.insert("title_key".into(), Value::String(key.to_string()));
415→        }
416→        if let Some(key) = detail_key {
417→            map.insert("detail_key".into(), Value::String(key.to_string()));
418→        }
419→        if let Some(params) = detail_params {
420→            map.insert("detail_params".into(), params);
421→        }
422→        if let Some(ts) = resets_at {
423→            // Send as milliseconds for the frontend.
424→            map.insert("resetsAt".into(), Value::Number((ts * 1000).into()));
425→        }
426→        if let Some(delay) = retry_after_ms {
427→            map.insert("retryAfterMs".into(), Value::Number(delay.into()));
428→        }
429→    }
430→    obj
431→}
432→
433→fn translation_keys_for(error_type: &str) -> (Option<&'static str>, Option<&'static str>) {
434→    match error_type {
435→        "usage_limit_reached" => (
436→            Some("errors:chat.usageLimitReached.title"),
437→            Some("errors:chat.usageLimitReached.detail"),
438→        ),
439→        "rate_limit_exceeded" => (
440→            Some("errors:chat.rateLimited.title"),
441→            Some("errors:chat.rateLimited.detail"),
442→        ),
443→        "auth_error" => (
444→            Some("errors:chat.authError.title"),
445→            Some("errors:chat.authError.detail"),
446→        ),
447→        "server_error" => (
448→            Some("errors:chat.serverError.title"),
449→            Some("errors:chat.serverError.detail"),
450→        ),
451→        "model_not_found" => (
452→            Some("errors:chat.modelNotFound.title"),
453→            Some("errors:chat.modelNotFound.detail"),
454→        ),
455→        "unsupported_model" => (Some("errors:chat.unsupportedModel.title"), None),
456→        "billing_exhausted" => (
457→            Some("errors:chat.billingExhausted.title"),
458→            Some("errors:chat.billingExhausted.detail"),
459→        ),
460→        "max_iterations_reached" => (
461→            Some("errors:chat.maxIterationsReached.title"),
462→            Some("errors:chat.maxIterationsReached.detail"),
463→        ),
464→        "api_error" | "unknown" => (Some("errors:generic.title"), None),
465→        _ => (None, None),
466→    }
467→}
