 64→/// Extract preview text from a single message JSON value.
 65→fn extract_preview_from_value(msg: &Value) -> Option<String> {
 66→    fn message_text(msg: &Value) -> Option<String> {
 67→        let text = if let Some(s) = msg.get("content").and_then(|v| v.as_str()) {
 68→            s.to_string()
 69→        } else if let Some(blocks) = msg.get("content").and_then(|v| v.as_array()) {
 70→            blocks
 71→                .iter()
 72→                .filter_map(|b| {
 73→                    if b.get("type").and_then(|v| v.as_str()) == Some("text") {
 74→                        b.get("text").and_then(|v| v.as_str())
 75→                    } else {
 76→                        None
 77→                    }
 78→                })
 79→                .collect::<Vec<_>>()
 80→                .join(" ")
 81→        } else {
 82→            return None;
 83→        };
 84→        let trimmed = text.trim();
 85→        if trimmed.is_empty() {
 86→            None
 87→        } else {
 88→            Some(trimmed.to_string())
 89→        }
 90→    }
 91→    fn truncate_preview(s: &str, max: usize) -> String {
 92→        if s.len() <= max {
 93→            s.to_string()
 94→        } else {
 95→            format!("{}…", &s[..s.floor_char_boundary(max)])
 96→        }
 97→    }
 98→    message_text(msg).map(|t| truncate_preview(&t, 200))
 99→}
