 71→/**
 72→ * Validate provider credentials without saving them.
 73→ * Returns { valid, models?, error? }.
 74→ */
 75→export async function validateProviderKey(provider, apiKey, baseUrl, model, requestId) {
 76→	var payload = { provider, apiKey };
 77→	if (baseUrl) payload.baseUrl = baseUrl;
 78→	if (model) payload.model = model;
 79→	if (requestId) payload.requestId = requestId;
 80→
 81→	var res = await sendRpc("providers.validate_key", payload);
 82→	if (!res?.ok) {
 83→		return {
 84→			valid: false,
 85→			error: humanizeProbeError(res?.error?.serverMessage || res?.error?.message || "Failed to validate credentials."),
 86→		};
 87→	}
 88→
 89→	var data = res.payload || {};
 90→	if (data.valid) {
 91→		return { valid: true, models: data.models || [] };
 92→	}
 93→	return {
 94→		valid: false,
 95→		error: humanizeProbeError(data.error || "Validation failed."),
 96→	};
 97→}
