 99→/**
100→ * Test a single model from the live registry.
101→ * Returns { ok, error? }.
102→ */
103→export async function testModel(modelId) {
104→	for (var attempt = 0; attempt < MODEL_TEST_RETRY_ATTEMPTS; attempt++) {
105→		var res = await sendRpc("models.test", { modelId });
106→		if (res?.ok) {
107→			return { ok: true };
108→		}
109→
110→		var message = res?.error?.serverMessage || res?.error?.message || "Model test failed.";
111→		var lower = String(message).toLowerCase();
112→		var shouldRetry = lower.includes(MODEL_SERVICE_NOT_CONFIGURED) && attempt < MODEL_TEST_RETRY_ATTEMPTS - 1;
113→
114→		if (!shouldRetry) {
115→			return {
116→				ok: false,
117→				error: humanizeProbeError(message),
118→			};
119→		}
120→
121→		await new Promise((resolve) => {
122→			window.setTimeout(resolve, MODEL_TEST_RETRY_DELAY_MS);
123→		});
124→	}
125→
126→	return {
127→		ok: false,
128→		error: humanizeProbeError("Model test failed."),
129→	};
130→}
