143→ * Persist provider credentials via the `providers.save_key` RPC.
144→ * Returns the RPC response (check `.ok` for success).
145→ */
146→export function saveProviderKey(providerName, apiKey, baseUrl, model) {
147→	var payload = buildSaveKeyPayload(providerName, apiKey, baseUrl, model);
