151→export async function validateProviderConnection(providerName) {
152→	var res = await sendRpc("models.detect_supported", {
153→		provider: providerName,
154→		reason: "provider_credentials_validation",
155→	});
156→
157→	if (!res?.ok) {
158→		return {
159→			ok: false,
160→			message: res?.error?.serverMessage || res?.error?.message || "Failed to validate provider credentials.",
161→		};
162→	}
163→
164→	var payload = res.payload || {};
165→	var total = payload.total || 0;
166→	var supported = payload.supported || 0;
167→	var unsupported = payload.unsupported || 0;
168→	var errors = payload.errors || 0;
169→
170→	if (supported > 0) {
171→		return {
172→			ok: true,
173→			message: null,
174→		};
175→	}
176→
177→	// No probe targets usually means no model is configured yet.
178→	if (total === 0) {
179→		return {
180→			ok: true,
181→			message: null,
182→		};
183→	}
184→
185→	var reason = firstProbeFailure(payload);
186→	if (!reason) {
187→		reason = `0/${total} models responded successfully (unsupported: ${unsupported}, errors: ${errors}).`;
188→	}
189→
190→	return {
191→		ok: false,
192→		message: `Credentials were saved, but validation failed: ${reason}`,
193→	};
194→}
