 7→
 8→function normalizeAttempt(value, fallback) {
 9→	if (!Number.isFinite(value)) return fallback;
10→	return Math.max(1, Math.floor(value));
11→}
12→
13→function stripModelNamespace(modelId) {
14→	if (!modelId || typeof modelId !== "string") return modelId;
15→	var sep = modelId.lastIndexOf("::");
16→	return sep >= 0 ? modelId.slice(sep + 2) : modelId;
17→}
18→
19→// biome-ignore lint/complexity/noExcessiveCognitiveComplexity: maps backend validation phases to progress UI updates.
20→function progressFromValidationEvent(payload) {
21→	if (!payload?.phase) return null;
22→	var phase = payload.phase;
23→	if (phase === "start") {
24→		return { value: 8, message: payload.message || "Starting provider validation..." };
25→	}
26→	if (phase === "candidates_discovered") {
27→		var count = Number.isFinite(payload.modelCount) ? payload.modelCount : null;
28→		var message = count == null ? "Discovered candidate models." : `Discovered ${count} candidate models.`;
29→		return { value: 24, message };
30→	}
31→	if (phase === "probe_started" || phase === "probe_failed" || phase === "probe_timeout") {
32→		var total = normalizeAttempt(payload.totalAttempts, 1);
33→		var attempt = Math.min(normalizeAttempt(payload.attempt, 1), total);
34→		var value = 24 + (attempt / total) * 62;
35→		var modelName = stripModelNamespace(payload.modelId);
36→		var defaultMessage = modelName
37→			? `Probing ${modelName} (${attempt}/${total})...`
38→			: `Probing model ${attempt}/${total}...`;
39→		return {
40→			value,
41→			message: payload.message || defaultMessage,
42→		};
43→	}
44→	if (phase === "probe_succeeded") {
45→		return { value: 94, message: payload.message || "Model probe succeeded." };
46→	}
47→	if (phase === "complete") {
48→		return { value: 100, message: payload.message || "Validation complete." };
49→	}
50→	if (phase === "error") {
51→		return { value: 98, message: payload.message || "Validation failed." };
52→	}
53→	return null;
54→}
55→
56→export function clampValidationProgressPercent(value) {
57→	if (!Number.isFinite(value)) return 0;
58→	return Math.max(0, Math.min(100, value));
59→}
60→
61→export function createValidationRequestId() {
62→	var nonce = Math.random().toString(36).slice(2, 10);
63→	return `validate-${Date.now()}-${nonce}`;
64→}
65→
66→export function subscribeValidationProgress(requestId, onProgress) {
67→	if (!(requestId && typeof onProgress === "function")) {
68→		return () => undefined;
69→	}
70→	var off = onEvent(VALIDATION_PROGRESS_EVENT, (payload) => {
71→		if (!payload || payload.requestId !== requestId) return;
72→		var update = progressFromValidationEvent(payload);
73→		if (!update) return;
74→		onProgress(update, payload);
75→	});
76→	return () => {
77→		off();
78→	};
79→}
