125→/// Convert session-crate `MessageContent` to agents-crate `UserContent`.
126→///
127→/// The two types have different image representations:
128→/// - `ContentBlock::ImageUrl` stores a data URI string
129→/// - `ContentPart::Image` stores separated `media_type` + `data` fields
130→fn to_user_content(mc: &MessageContent) -> UserContent {
131→    match mc {
132→        MessageContent::Text(text) => UserContent::Text(text.clone()),
133→        MessageContent::Multimodal(blocks) => {
134→            let parts: Vec<ContentPart> = blocks
135→                .iter()
136→                .filter_map(|block| match block {
137→                    ContentBlock::Text { text } => Some(ContentPart::Text(text.clone())),
138→                    ContentBlock::ImageUrl { image_url } => match parse_data_uri(&image_url.url) {
139→                        Some((media_type, data)) => {
140→                            debug!(
141→                                media_type,
142→                                data_len = data.len(),
143→                                "to_user_content: parsed image from data URI"
144→                            );
145→                            Some(ContentPart::Image {
146→                                media_type: media_type.to_string(),
147→                                data: data.to_string(),
148→                            })
149→                        },
150→                        None => {
151→                            warn!(
152→                                url_prefix = truncate_at_char_boundary(&image_url.url, 80),
153→                                "to_user_content: failed to parse data URI, dropping image"
154→                            );
155→                            None
156→                        },
157→                    },
158→                })
159→                .collect();
160→            let text_count = parts
161→                .iter()
162→                .filter(|p| matches!(p, ContentPart::Text(_)))
163→                .count();
164→            let image_count = parts
165→                .iter()
166→                .filter(|p| matches!(p, ContentPart::Image { .. }))
167→                .count();
168→            debug!(
169→                text_count,
170→                image_count,
171→                total_blocks = blocks.len(),
172→                "to_user_content: converted multimodal content"
173→            );
174→            UserContent::Multimodal(parts)
175→        },
176→    }
177→}
