179→fn rewrite_multimodal_text_blocks(blocks: &[ContentBlock], new_text: &str) -> Vec<ContentBlock> {
180→    let mut rewritten = Vec::with_capacity(blocks.len().max(1));
181→    let mut inserted_text = false;
182→
183→    for block in blocks {
184→        match block {
185→            ContentBlock::Text { .. } if !inserted_text => {
186→                rewritten.push(ContentBlock::Text {
187→                    text: new_text.to_string(),
188→                });
189→                inserted_text = true;
190→            },
191→            ContentBlock::Text { .. } => {},
192→            _ => rewritten.push(block.clone()),
193→        }
194→    }
195→
196→    if !inserted_text {
197→        rewritten.insert(0, ContentBlock::Text {
198→            text: new_text.to_string(),
199→        });
200→    }
201→
202→    rewritten
203→}
