205→fn apply_message_received_rewrite(
206→    message_content: &mut MessageContent,
207→    params: &mut Value,
208→    new_text: &str,
209→) {
210→    match message_content {
211→        MessageContent::Text(text) => {
212→            *text = new_text.to_string();
213→            if let Some(params_obj) = params.as_object_mut() {
214→                params_obj.insert("text".to_string(), serde_json::json!(new_text));
215→                params_obj.remove("content");
216→            }
217→        },
218→        MessageContent::Multimodal(blocks) => {
