 817→fn explicit_reply_medium_override(text: &str) -> Option<ReplyMedium> {
 818→    let lower = text.to_lowercase();
 819→    let voice_markers = [
 820→        "talk to me",
 821→        "say it",
 822→        "say this",
 823→        "speak",
 824→        "voice message",
 825→        "respond with voice",
 826→        "reply with voice",
 827→        "audio reply",
 828→    ];
 829→    if voice_markers.iter().any(|m| lower.contains(m)) {
 830→        return Some(ReplyMedium::Voice);
 831→    }
 832→
 833→    let text_markers = [
 834→        "text only",
 835→        "reply in text",
 836→        "respond in text",
 837→        "don't use voice",
 838→        "do not use voice",
 839→        "no audio",
 840→    ];
 841→    if text_markers.iter().any(|m| lower.contains(m)) {
 842→        return Some(ReplyMedium::Text);
 843→    }
 844→
 845→    None
 846→}
