 848→fn infer_reply_medium(params: &Value, text: &str) -> ReplyMedium {
 849→    if let Some(explicit) = explicit_reply_medium_override(text) {
 850→        return explicit;
 851→    }
 852→
 853→    if let Some(input_medium) = parse_input_medium(params) {
 854→        return input_medium;
 855→    }
 856→
 857→    if let Some(channel) = params
 858→        .get("channel")
 859→        .cloned()
 860→        .and_then(|v| serde_json::from_value::<InputChannelMeta>(v).ok())
 861→        && channel.message_kind == Some(InputMessageKind::Voice)
 862→    {
 863→        return ReplyMedium::Voice;
 864→    }
 865→
 866→    ReplyMedium::Text
 867→}
