 892→fn capped_tool_result_payload(result: &Value, max_len: usize) -> Value {
 893→    let mut capped = result.clone();
 894→    for field in &["stdout", "stderr"] {
 895→        if let Some(text) = capped.get(*field).and_then(Value::as_str)
 896→            && text.len() > max_len
 897→        {
 898→            let truncated = format!(
 899→                "{}\n\n... [truncated — {} bytes total]",
 900→                truncate_at_char_boundary(text, max_len),
 901→                text.len()
 902→            );
 903→            capped[*field] = Value::String(truncated);
 904→        }
 905→    }
 906→    capped
 907→}
