 909→fn shell_reply_text_from_exec_result(result: &Value) -> String {
 910→    let stdout = result
 911→        .get("stdout")
 912→        .and_then(Value::as_str)
 913→        .map(str::trim_end)
 914→        .unwrap_or("");
 915→    if !stdout.is_empty() {
 916→        return stdout.to_string();
 917→    }
 918→
 919→    let stderr = result
 920→        .get("stderr")
 921→        .and_then(Value::as_str)
 922→        .map(str::trim_end)
 923→        .unwrap_or("");
 924→    if !stderr.is_empty() {
 925→        return stderr.to_string();
 926→    }
 927→
 928→    let exit_code = result.get("exit_code").and_then(Value::as_i64).or_else(|| {
 929→        result
 930→            .get("exit_code")
 931→            .and_then(Value::as_u64)
 932→            .and_then(|code| i64::try_from(code).ok())
 933→    });
 934→    match exit_code {
 935→        Some(code) if code != 0 => format!("Command failed (exit {code})."),
 936→        _ => String::new(),
 937→    }
 938→}
