1011→                } else if stderr.contains("not in the sudoers")
1012→                    || stderr.contains("is not in the sudoers")
1013→                    || stderr.contains("is not allowed to run sudo")
1014→                    || stderr.contains("may not run sudo")
1015→                {
1016→                    (Some(false), Some("denied".to_string()))
1017→                } else {
1018→                    (None, Some("unknown".to_string()))
1019→                }
1020→            },
1021→            Err(e) if e.kind() == std::io::ErrorKind::NotFound => {
