207→/// Convert tool schemas to OpenAI Chat Completions function-calling format.
208→///
209→/// Uses the nested `function` object format required by Chat Completions API:
210→/// ```json
211→/// { "type": "function", "function": { "name": "...", ... } }
212→/// ```
213→///
214→/// Adds `strict: true` and patches schemas for strict mode compliance:
215→/// - `additionalProperties: false` on all object schemas
216→/// - All properties included in `required` array
217→///
218→/// This is required by some APIs (Claude via Copilot) to ensure the model
219→/// provides all required fields.
220→///
221→/// See: <https://platform.openai.com/docs/guides/function-calling>
222→pub fn to_openai_tools(tools: &[serde_json::Value]) -> Vec<serde_json::Value> {
223→    let result: Vec<serde_json::Value> = tools
224→        .iter()
225→        .filter_map(|t| {
226→            // Clone parameters and patch for strict mode
227→            let mut params = t["parameters"].clone();
228→            patch_schema_for_strict_mode(&mut params);
229→
230→            let name = t["name"].as_str()?.to_string();
231→            let description = t["description"].as_str().unwrap_or("").to_string();
232→
233→            // Use typed struct to ensure all required fields are present
234→            let tool = ChatCompletionsTool {
235→                tool_type: "function",
236→                function: ChatCompletionsFunction {
237→                    name: name.clone(),
238→                    description,
239→                    parameters: params,
240→                    strict: true,
241→                },
242→            };
243→
244→            trace!(tool_name = %name, "converted tool to Chat Completions format");
245→
246→            // Serialize to Value for compatibility with existing API
247→            serde_json::to_value(tool).ok()
248→        })
249→        .collect();
250→
251→    trace!(tools_count = result.len(), "to_openai_tools complete");
252→    result
253→}
