446→        return Some(usage);
447→    }
448→
449→    if let Some(usage) = payload
450→        .get("choices")
451→        .and_then(serde_json::Value::as_array)
452→        .and_then(|choices| choices.first())
453→        .and_then(|choice| choice.get("delta"))
454→        .and_then(|delta| delta.get("usage"))
455→        .filter(|usage| usage.is_object())
456→    {
457→        return Some(usage);
458→    }
459→
460→    if let Some(usage) = payload
461→        .get("choices")
462→        .and_then(serde_json::Value::as_array)
463→        .and_then(|choices| choices.first())
464→        .and_then(|choice| choice.get("message"))
465→        .and_then(|message| message.get("usage"))
466→        .filter(|usage| usage.is_object())
467→    {
468→        return Some(usage);
469→    }
470→
471→    payload
472→        .get("x_groq")
473→        .and_then(|x_groq| x_groq.get("usage"))
474→        .filter(|usage| usage.is_object())
475→}
