 84→/// Normalize the `redirect_uri` on a provider `OAuthConfig` loaded via
 85→/// `load_oauth_config` so that loopback values always use the `http`
 86→/// scheme, per RFC 8252 §7.3/§8.3.
 87→///
 88→/// Built-in defaults (e.g. `openai-codex`) already use
 89→/// `http://localhost:1455/auth/callback`, but `load_oauth_config` also
 90→/// reads from `~/.config/moltis/oauth_providers.json` and
 91→/// `MOLTIS_OAUTH_{PROVIDER}_REDIRECT_URI`, either of which could
 92→/// accidentally specify `https://localhost`. Without normalization:
 93→///
 94→/// * `callback_port` would parse the port from the HTTPS form and the
 95→///   spawned `CallbackServer` would try to bind on Moltis's main TLS
 96→///   port, which is already in use by the gateway.
 97→/// * Strict authorization servers would reject the authorization
 98→///   request with `invalid_redirect_uri`.
 99→///
100→/// No-op for empty or non-loopback URIs.
101→fn normalize_loaded_redirect_uri(config: &mut moltis_oauth::OAuthConfig) {
102→    if config.redirect_uri.is_empty() {
103→        return;
104→    }
105→    config.redirect_uri = normalize_loopback_redirect(&config.redirect_uri);
106→}
