1418→            );
1419→
1420→            let effective = {
1421→                let base = config.lock().unwrap_or_else(|e| e.into_inner()).clone();
1422→                config_with_saved_keys(&base, &key_store, &[])
1423→            };
1424→
1425→            let new_registry = match tokio::task::spawn_blocking(move || {
1426→                ProviderRegistry::from_env_with_config_and_overrides(&effective, &env_overrides)
