553→struct StartupMemProbe {
554→    enabled: bool,
555→    last_rss_bytes: u64,
556→}
557→
558→impl StartupMemProbe {
559→    fn new() -> Self {
560→        let enabled = env_flag_enabled("MOLTIS_STARTUP_MEM_TRACE");
561→        let last_rss_bytes = if enabled {
562→            process_rss_bytes()
563→        } else {
564→            0
565→        };
566→        Self {
567→            enabled,
568→            last_rss_bytes,
569→        }
570→    }
571→
572→    fn checkpoint(&mut self, stage: &str) {
573→        if !self.enabled {
574→            return;
575→        }
576→        let rss_bytes = process_rss_bytes();
577→        let delta_bytes = rss_bytes as i128 - self.last_rss_bytes as i128;
578→        self.last_rss_bytes = rss_bytes;
579→
580→        info!(
581→            stage,
582→            rss_bytes,
583→            delta_bytes = delta_bytes as i64,
584→            "startup memory checkpoint"
585→        );
586→    }
587→}
