 78→function fetchProviders() {
 79→	loading.value = true;
 80→	return Promise.all([sendRpc("models.list_all", {}), sendRpc("providers.available", {})])
 81→		.then(([modelsRes, providersRes]) => {
 82→			loading.value = false;
 83→			var providerMeta = new Map();
 84→			var configuredProviders = [];
 85→			if (providersRes?.ok) {
 86→				configuredProviders = (providersRes.payload || []).filter(
 87→					(configuredProvider) => configuredProvider.configured,
 88→				);
 89→				for (var providerMetaEntry of providersRes.payload || []) {
 90→					providerMeta.set(providerMetaEntry.name, providerMetaEntry);
 91→				}
 92→			}
 93→			providerMetaSig.value = providerMeta;
 94→
 95→			var models = [];
 96→			if (modelsRes?.ok) {
 97→				models = (modelsRes.payload || []).map((m) => ({
 98→					...m,
 99→					providerDisplayName: providerMeta.get(m.provider)?.displayName || m.provider,
100→					authType: providerMeta.get(m.provider)?.authType || "api-key",
101→				}));
102→			}
103→
104→			// Include configured providers that don't currently expose a model.
105→			var modelProviders = new Set(models.map((m) => m.provider));
106→			var providerOnlyRows = [];
107→			providerOnlyRows = configuredProviders
108→				.filter((providerWithoutModels) => !modelProviders.has(providerWithoutModels.name))
109→				.map((providerWithoutModels) => ({
