111→					provider: providerWithoutModels.name,
112→					displayName: providerWithoutModels.displayName,
113→					providerDisplayName: providerWithoutModels.displayName,
114→					providerOnly: true,
115→					authType: providerWithoutModels.authType,
116→				}));
117→
118→			configuredModels.value = [...models, ...providerOnlyRows];
119→			updateNavCount("providers", countUniqueProviders(configuredModels.value));
120→		})
