126→async function runDetectAllModels() {
127→	if (!connected.value || detectingModels.value) return;
128→	detectingModels.value = true;
129→	detectSummary.value = null;
130→	detectError.value = "";
131→	detectProgress.value = null;
132→
133→	try {
134→		// Phase 1: show current full list first before probing.
135→		await Promise.all([fetchModels(), fetchProviders()]);
136→		await new Promise((resolve) => {
137→			requestAnimationFrame(resolve);
138→		});
139→
140→		var res = await sendRpc("models.detect_supported", {});
141→		if (!res?.ok) {
142→			detectError.value = res?.error?.message || t("providers:failedToDetectModels");
143→			detectingModels.value = false;
144→			return;
145→		}
146→		if (res.payload?.skipped) {
147→			detectingModels.value = false;
148→			return;
149→		}
150→		detectSummary.value = res.payload || null;
151→		detectProgress.value = progressFromPayload(res.payload);
152→		await Promise.all([fetchModels(), fetchProviders()]);
153→		var p = detectProgress.value;
154→		if (!p || p.total === 0 || p.checked >= p.total) {
155→			detectingModels.value = false;
156→		}
157→	} catch (_err) {
158→		detectingModels.value = false;
159→	}
160→}
