169→function groupProviderRows(models, metaMap) {
170→	var groups = new Map();
171→	for (var row of models) {
172→		var key = row.provider;
173→		if (!groups.has(key)) {
174→			groups.set(key, {
175→				provider: key,
176→				providerDisplayName: row.providerDisplayName || row.displayName || key,
177→				authType: row.authType || "api-key",
178→				selectedModel: metaMap?.get(key)?.model || null,
179→				models: [],
180→			});
181→		}
182→		var groupEntry = groups.get(key);
183→		if (!row.providerOnly) {
184→			groupEntry.models.push(row);
185→		}
186→	}
187→
188→	var result = Array.from(groups.values());
189→	result.sort((a, b) => {
190→		var aOrder = metaMap?.get(a.provider)?.uiOrder;
191→		var bOrder = metaMap?.get(b.provider)?.uiOrder;
192→		var hasAOrder = Number.isFinite(aOrder);
193→		var hasBOrder = Number.isFinite(bOrder);
194→		if (hasAOrder && hasBOrder && aOrder !== bOrder) return aOrder - bOrder;
195→		if (hasAOrder && !hasBOrder) return -1;
196→		if (!hasAOrder && hasBOrder) return 1;
197→		return a.providerDisplayName.localeCompare(b.providerDisplayName);
198→	});
199→	for (var providerGroup of result) {
200→		providerGroup.models.sort((a, b) => {
201→			// Preferred > recommended > newest date > highest version number > alpha.
202→			var aPref = a.preferred ? 1 : 0;
203→			var bPref = b.preferred ? 1 : 0;
204→			if (aPref !== bPref) return bPref - aPref;
205→			var aRec = a.recommended ? 1 : 0;
206→			var bRec = b.recommended ? 1 : 0;
207→			if (aRec !== bRec) return bRec - aRec;
208→			var aTime = a.createdAt || 0;
209→			var bTime = b.createdAt || 0;
210→			if (aTime !== bTime) return bTime - aTime;
211→			var aVer = modelVersionScore(a.id);
212→			var bVer = modelVersionScore(b.id);
213→			if (aVer !== bVer) return bVer - aVer;
214→			return (a.displayName || a.id).localeCompare(b.displayName || b.id);
215→		});
216→	}
217→	return result;
218→}
