        assert_eq!(result.get("valid").and_then(|v| v.as_bool()), Some(false));
        let error = result.get("error").and_then(|v| v.as_str()).unwrap_or("");
        assert!(
            error.contains("Failed to discover models"),
            "should report discovery failure, got: {error}"
